import { isString, isUndefined } from 'lodash-es';
import {
  type HTMLAttributes,
  type PropsWithChildren,
  type ReactElement,
  type ReactNode,
} from 'react';

import { Flex } from '../../../../../../../layouts/flex/Flex.js';
import type { SeriesActionsTemplate } from '../../../../../types/series-actions-template.js';
import { EmojiShape } from '../../../../shape/EmojiShape/EmojiShape.js';
import { IconShape } from '../../../../shape/IconShape/IconShape.js';
import { PrimaryAtom } from '../../../../tooltip-atoms/components/PrimaryAtom.js';
import { SecondaryAtom } from '../../../../tooltip-atoms/components/SecondaryAtom.js';
import { TooltipItem } from '../../../section-components/TooltipItem/TooltipItem.js';
import { TooltipSymbolContent } from '../../../section-components/TooltipSymbolContent/TooltipSymbolContent.js';
import type { TooltipItemProps } from '../../../types/tooltip.js';

/** @internal */
export interface EvenItemProps
  extends HTMLAttributes<HTMLDivElement>,
    Pick<TooltipItemProps, 'showDivider'> {
  title?: string;
  description?: string;
  icon?: ReactNode | string;
  actions?: () => SeriesActionsTemplate;
  defaultActions?: ReactElement<PropsWithChildren>;
}

/** @internal */
export const EventItem = ({
  description,
  icon,
  title,
  actions,
  className,
  showDivider,
  ...rest
}: EvenItemProps) => {
  return (
    <TooltipItem
      actions={actions}
      className={className}
      showDivider={showDivider}
      {...rest}
    >
      <Flex alignItems="center">
        {icon && (
          <TooltipSymbolContent>
            {isString(icon) ? (
              <EmojiShape>{icon}</EmojiShape>
            ) : (
              <IconShape>{icon}</IconShape>
            )}
          </TooltipSymbolContent>
        )}
        <Flex flexDirection="column" gap={0}>
          <PrimaryAtom style={{ textAlign: 'left' }}>{title}</PrimaryAtom>
          {!isUndefined(description) && (
            <SecondaryAtom style={{ textAlign: 'left' }}>
              {description}
            </SecondaryAtom>
          )}
        </Flex>
      </Flex>
    </TooltipItem>
  );
};

EventItem['displayName'] = 'ChartTooltip.EventItem';
